import{_ as o,o as t,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"Sonoff RFR3 DIY — 433 MHz MQTT gateway mod","description":"Notes on Sonoff RFR3 DIY — 433 MHz MQTT gateway mod.","frontmatter":{"title":"Sonoff RFR3 DIY — 433 MHz MQTT gateway mod","description":"Notes on Sonoff RFR3 DIY — 433 MHz MQTT gateway mod."},"headers":[],"relativePath":"microcontrollers-and-socs/vivio-wordpress-com-sonoff-rfr3-433-mqtt-gateway-mod.md","filePath":"microcontrollers-and-socs/vivio-wordpress-com-sonoff-rfr3-433-mqtt-gateway-mod.md"}'),s={name:"microcontrollers-and-socs/vivio-wordpress-com-sonoff-rfr3-433-mqtt-gateway-mod.md"};function n(i,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="sonoff-rfr3-diy-—-433-mhz-mqtt-gateway-mod" tabindex="-1">Sonoff RFR3 DIY — 433 MHz MQTT gateway mod <a class="header-anchor" href="#sonoff-rfr3-diy-—-433-mhz-mqtt-gateway-mod" aria-label="Permalink to &quot;Sonoff RFR3 DIY — 433 MHz MQTT gateway mod&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://vivio.wordpress.com/2020/04/23/sonoff-rfr3-433-mqtt-gateway-mod/" target="_blank" rel="noreferrer">https://vivio.wordpress.com/2020/04/23/sonoff-rfr3-433-mqtt-gateway-mod/</a></li><li>Imported: 2026-05-10</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>The author wanted a UV-C lamp control setup with:</p><ol><li>Start the lamp from a remote</li><li>Turn the lamp off if a PIR sensor or door opens</li><li>Prevent turning the lamp on unless PIR and door are closed</li></ol><p>Wi-Fi was kept for monitoring only (unreliable router). Intended signal path: PIR2 / remote / door sensor → RF Bridge → RFR3 relay.</p><p><strong>Limitation:</strong> The Sonoff RF Bridge can learn RF sensors and send RF to the relay, but simple RF did not expose relay state reliably. The <strong>Sonoff RFR3 DIY</strong> has Wi-Fi and RF but is not a stock RF gateway. The goal was an <strong>RF gateway with a relay</strong> that can decode RF sensor traffic and expose <strong>relay state</strong>.</p><p>Credits and references:</p><ul><li><a href="https://tech.scargill.net/user/mrshark/" target="_blank" rel="noreferrer">DrFragle and MrShark</a> — discussion on <a href="https://tech.scargill.net/sonoff-rf-bridge/#comment-66682" target="_blank" rel="noreferrer">Scargill’s blog (Sonoff RF Bridge)</a></li><li>Inspired by <a href="https://1technophile.blogspot.com/2019/08/new-sonoff-rfr3-as-433tomqtt-gateway.html" target="_blank" rel="noreferrer">1 TECHNOPHILE — New Sonoff RFR3 as 433ToMQTT gateway</a></li></ul><h3 id="flash-tasmota" tabindex="-1">Flash Tasmota <a class="header-anchor" href="#flash-tasmota" aria-label="Permalink to &quot;Flash Tasmota&quot;">​</a></h3><ul><li>Flash <strong>Tasmota</strong> on the Sonoff RFR3 DIY. The author notes that eWeLink app firmware 3.5 broke DIY mode; <strong>USB-to-UART at 3.3 V</strong> was required for flashing.</li><li>Use the <strong><code>tasmota-sensors.bin</code></strong> build from <a href="https://github.com/arendst/Tasmota/releases" target="_blank" rel="noreferrer">Tasmota releases</a> (full sensor build).</li></ul><h3 id="hardware-modification-rf-chip" tabindex="-1">Hardware modification (RF chip) <a class="header-anchor" href="#hardware-modification-rf-chip" aria-label="Permalink to &quot;Hardware modification (RF chip)&quot;">​</a></h3><p>On the board, <strong>desolder the SMD resistor</strong> on the RF chip side and <strong>solder a wire</strong> to the terminal described in the TECHNOPHILE article. TECHNOPHILE suggests <strong>cutting a copper trace</strong>; the author <strong>removed the resistor</strong> entirely as cleaner.</p><p><strong>GPIO choice:</strong> TECHNOPHILE uses <strong>GPIO4</strong>, which the author found hard to solder. <strong><a href="https://www.youtube.com/channel/UC5ZdPKE2ckcBhljTc2R_qNA" target="_blank" rel="noreferrer">Digiblur</a></strong> used <strong>GPIO1</strong> as input (ESP <strong>TX</strong> pin on their diagram). The author soldered <strong>GPIO1</strong> for easier access.</p><p><strong>Enclosure:</strong> The extra wire can stop the PCB from sitting flat in the bottom shell and block the tall switch in the top shell — the author <strong>slightly enlarged a hole</strong> in the upper shell so the assembly fits.</p><h3 id="tasmota-configuration" tabindex="-1">Tasmota configuration <a class="header-anchor" href="#tasmota-configuration" aria-label="Permalink to &quot;Tasmota configuration&quot;">​</a></h3><p>From <a href="https://discord.gg/Ks2Kzd4" target="_blank" rel="noreferrer">Tasmota Discord</a> (thanks to barbudor, Seth, squalazzo): after this mod you cannot use the stock <strong>Sonoff RF bridge</strong> template on the RFR3. Use <strong>RC-Switch</strong> behavior by assigning the GPIO wired to the RF receiver as <strong>RF Recv (106)</strong>.</p><p>Because the author wired <strong>GPIO1</strong>, in <strong>Configuration → Configure Module</strong> set <strong>GPIO1</strong> to <strong>RF Recv (106)</strong>.</p><p>After saving, the <strong>Console</strong> should show RF reception alongside relays.</p><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>One-off issue: after a <strong>full power cycle</strong>, the relay once came up <strong>on</strong>; could not reproduce.</li></ul><p><strong>Safety:</strong> Original post includes UV-C and mains safety disclaimers — follow electrical and UV safety practices.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Sonoff RFR3 can be modded (RF chip resistor removal / reroute + wire) to act as a <strong>433 MHz receive path</strong> into Tasmota, similar in spirit to the RF Bridge + MQTT gateway approach.</li><li>Prefer <strong><code>tasmota-sensors.bin</code></strong> for this use case; flash via UART if eWeLink/DIY mode is broken.</li><li>Use <strong>RF Recv (106)</strong> on the GPIO you actually soldered (author used <strong>GPIO1</strong> instead of GPIO4 for easier soldering).</li><li>Expect to adjust the <strong>case</strong> so internal routing does not jam the mechanical switch.</li></ul>',26)])])}const m=o(s,[["render",n]]);export{f as __pageData,m as default};
